        elif any(w in text for w in ['league', 'cup', 'team', 'player', 'coach', 'stadium', 'ball', 'score', 'win', 'season']):
            scores['Sports'] += 1

    # "security" in tech vs world
    if 'security' in tokens:
        if any(w in text for w in ['internet', 'web', 'software', 'virus', 'hacker', 'computer', 'network']):
            scores['Sci/Tech'] += 2
        elif any(w in text for w in ['border', 'national', 'council', 'un', 'iraq', 'war', 'police']):
